 49→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
 50→  return {
 51→    ...project,
 52→    floors: project.floors.map((floor) => ({
 53→      ...floor,
 54→      stairs: (floor.stairs || []).map((stair) => ({
 55→        ...stair,
 56→        floorRelation: {
 57→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
 58→            ? fallbackFloorId
 59→            : (stair.floorRelation?.fromFloorId ?? floor.id),
 60→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
 61→            ? fallbackFloorId
 62→            : (stair.floorRelation?.toFloorId ?? floor.id),
 63→        },
 64→      })),
 65→    })),
 66→    sheets: (project.sheets || []).map((sheet) => ({
 67→      ...sheet,
 68→      viewports: (sheet.viewports || []).map((viewport) => ({
 69→        ...viewport,
 70→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
 71→          ? fallbackFloorId
 72→          : viewport.sourceFloorId,
 73→        sourceRefId: viewport.sourceFloorId === deletedFloorId
 74→          ? null
 75→          : viewport.sourceRefId,
 76→      })),
 77→    })),
 78→  };
 79→}
