 81→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 82→  const nextWall = { ...existingWall, ...wallUpdate };
 83→
 84→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 85→    nextWall.startAttachment = null;
 86→  }
 87→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 88→    nextWall.endAttachment = null;
 89→  }
 90→
 91→  return syncWallAttachmentPoints(nextWall, columns);
 92→}
