 16→const SHEET_PREVIEW_OPTIONS = {
 17→  width: 1600,
 18→  height: 1000,
 19→  preset: 'iso_northeast',
 20→};
 21→const sheetPreviewCache = new Map();
 22→
 23→function getSheetPreviewCacheKey(source) {
 24→  return [
 25→    source?.project?.id || 'project',
 26→    source?.project?.updatedAt || 'snapshot',
 27→    source?.activeFloorId || 'all',
 28→    SHEET_PREVIEW_OPTIONS.width,
 29→    SHEET_PREVIEW_OPTIONS.height,
 30→    SHEET_PREVIEW_OPTIONS.preset,
 31→  ].join(':');
 32→}
 33→
 34→function renderSheetPreviewImage(source) {
 35→  const cacheKey = getSheetPreviewCacheKey(source);
 36→  if (!sheetPreviewCache.has(cacheKey)) {
 37→    sheetPreviewCache.set(cacheKey, import('@/three/viewer/renderToImage')
 38→      .then(({ renderSceneToImage }) => {
 39→        const imageUrl = renderSceneToImage(source.project, {
 40→          activeFloorId: source.activeFloorId,
 41→          width: SHEET_PREVIEW_OPTIONS.width,
 42→          height: SHEET_PREVIEW_OPTIONS.height,
 43→          preset: SHEET_PREVIEW_OPTIONS.preset,
 44→        });
 45→
 46→        return imageUrl
 47→          ? { status: 'ready', imageUrl }
 48→          : { status: 'empty', imageUrl: null };
 49→      })
 50→      .catch((error) => {
 51→        sheetPreviewCache.delete(cacheKey);
 52→        throw error;
 53→      }));
 54→  }
 55→
 56→  return sheetPreviewCache.get(cacheKey);
 57→}
